// ▶조회조건
//   실적기간 : 2022/01/01 ~ 2022/01/31 / 2022/01/31 ~ 2022/01/31
//   계약거래처 : 315946
//   화주구분 : 화주

scwin.memJson = $c.data.getMemInfo($p);
scwin.loUpperLobranCd = scwin.memJson.loUpperLobranCd; //상위물류점소코드
scwin.sUserId = scwin.memJson.userId;
if (scwin.loUpperLobranCd == null) {
  scwin.loUpperLobranCd = "";
}
scwin.strCurrDate = $c.date.getServerDateTime($p, "yyyyMMdd");
scwin.curDate = scwin.strCurrDate.substring(0, 6);
scwin.lastDate = scwin.curDate + $c.date.getLastDateOfMonth($p, scwin.strCurrDate);

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = async function () {
  scwin.params = $c.data.getParameter($p);
  var lobranCd = $c.gus.cfIsNull($p, scwin.params["lobranCd"]) ? "" : scwin.params["lobranCd"];
  const param = [{
    method: "getLuxeComboData",
    param1: "WorkImplementEBC",
    param2: "retriveLobran2CodeList",
    param3: ["1"],
    compID: "lc_wrkLobranCd" // 점소
  }];
  await $c.data.setGauceUtil($p, param, function () {
    lc_wrkLobranCd.addItem("국제물류", "1GG", true, 1);
    if (lobranCd == "") {
      lc_wrkLobranCd.setValue(scwin.loUpperLobranCd);
    } else {
      lc_wrkLobranCd.setValue(lobranCd);
    }
  });
};
scwin.onUdcCompleted = function () {
  const codeOptions = [{
    grpCd: "OP917",
    compID: "ed_rsnCd"
  },
  //미신고사유
  {
    grpCd: "OP913",
    compID: "ed_clsCd"
  } //비정상사유
  ];
  $c.data.setCommonCode($p, codeOptions);
  ed_odrNoCh.setValue("0");
  ed_clntGubun.setValue("0");
  ed_bilgClntCls.setValue("");
  em_rsltsStdDt.setValue(scwin.curDate + "01");
  em_rsltsEndDt.setValue(scwin.lastDate);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  // var stdDt = em_rsltsStdDt.getValue();
  // var endDt = em_rsltsEndDt.getValue();

  // 실적기간 From - To 입력 확인
  if (!(await $c.gus.cfValidate($p, [em_rsltsStdDt, em_rsltsEndDt]))) {
    return;
  }

  // 실적기간 범위 확인
  if (!(await $c.gus.cfIsAfterDate($p, em_rsltsStdDt.getValue(), em_rsltsEndDt.getValue()))) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_048, ["실적일자 From", "실적일자 To"]);
    em_rsltsStdDt.focus();
    return false;
  }
  var diffObj = await $c.gus.cfDifferBetween($p, em_rsltsStdDt.getValue(), em_rsltsEndDt.getValue());

  // 실적기간  3달 이상인경우 확인
  if (lc_wrkLobranCd.getValue() == "") {
    //점소 전체 조회 시 
    if (diffObj.year > 0 || diffObj.month > 0) {
      await $c.win.alert($p, "실적기간  1개월까지 조회가능합니다.");
      em_rsltsEndDt.focus();
      return false;
    }
  } else {
    //특정점소로 조회 시 최대 3개월까지
    if (diffObj.year > 0 || diffObj.month > 3) {
      await $c.win.alert($p, "실적기간 최대 3개월까지 조회가능합니다.");
      em_rsltsEndDt.focus();
      return false;
    }
  }
  $c.sbm.execute($p, sbm_retrieve);
};

//-------------------------------------------
// 그리드 데이터 엑셀로 다운
//-------------------------------------------
scwin.f_runExcel = async function () {
  if (ds_results.getTotalRow() != 0) {
    var cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      var fileName = "화물운송실적신고(정상)";
      var options = {
        fileName: fileName + ".xlsx",
        sheetName: fileName,
        colMerge: true,
        colMergeTextAlign: "top"
      };
      await $c.data.downloadGridViewExcel($p, gr_results, options);
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
  }
};
