//-------------------------------------------------------------------------
// f_ChangeVehclToPchs 
// 체크된 화물운송실적신고(정상) 건 위수탁(배차)건 협력(위탁)으로 변경_부산지사 운송팀 김태규가 요청

// 협력구분을 배차협력업체를 조회하지 않은경우 RETURN;
// 협력업체번호를 작성하지 않은경우 RETURN;
// 그리드에 데이터가 존재하지 않는경우 RETURN;
// vehclClntNo==NULL이면 위탁협력업체이므로 RETURN;
// stateCd!='0','2'이면 엑셀업로드(915)한경우 이므로 RETURN;
//-------------------------------------------------------------------------
scwin.f_changeVehclToPchs = async function () {
  // 협력구분을 배차협력업체를 조회하지 않은경우 RETURN;
  // 협력업체번호를 작성하지 않은경우 RETURN;
  // 그리드에 데이터가 존재하지 않는경우 RETURN;
  if (ed_pchsClntNo.getValue() == '' || ed_clntGubun.getValue() == '0' || !(ds_results.getTotalRow() > 0)) {
    await $c.win.alert($p, "배차협력업체를 조회하세요");
    return;
  }
  var check = false;
  for (var i = 0; i < ds_results.getTotalRow(); i++) {
    //stateCd!='0'이면 엑셀업로드(915)한경우 이므로 변경할수없음
    var stateCd = ds_results.getCellData(i, "stateCd");
    if (stateCd != '0' && stateCd != '2') {
      //stateCd='0'이면 정상 ,stateCd='2'이면 전환  statecd='엑셀업로드' 이면 엑셀업로드
      await $c.win.alert($p, "엑셀업로드한 경우에는 변경할 수 없습니다.");
      return;
    }

    //vehclClntNo==NULL이면 위탁협력업체
    var vehclClntNo = ds_results.getCellData(i, "vehclClntNo"); //배차협력업체인경우 존재
    if (vehclClntNo == '' || vehclClntNo == null) {
      ds_results.setCellData(i, "clntGubun", 0); //위탁협력업체
      await $c.win.alert($p, "위탁협력업체인경우 변경할수 없습니다.");
      return;
    }

    //pchsClntNo==NULL이면 배차협력업체
    var pchsClntNo = ds_results.getCellData(i, "pchsClntNo"); //위탁협력업체인경우 존재
    if (pchsClntNo == '' || pchsClntNo == null) {
      ds_results.setCellData(i, "clntGubun", 1); //배차협력업체
      check = true;
    }
  }
  if (check) {
    if (await $c.win.confirm($p, "변경된 후 되돌릴 수 없습니다. 변경하시겠습니까?")) {
      // ds_results.UseChangeInfo = false;
      $c.sbm.execute($p, sbm_changeVehclToPchs);
    }
  }
};

// 20170927 무매출에대해 매입금액을 만드는 프로시져가 있어 기능을 더이상 사용하지 않는것같음 
//-------------------------------------------------------------------------
// f_CreateSellAmt 
// 이런저러한사유로 무매출된 오더번호 매출금액 만들어주는 버튼 _부산지사 운송팀 김태규가 요청
//-------------------------------------------------------------------------
scwin.f_createSellAmt = async function () {
  // 전송상태에서는 수정이 불가하도록 
  if (!(await scwin.f_chkBeforeSave())) {
    return;
  }
  if (ed_odrNo.getValue() == '' || !(ds_results.getTotalRow() > 0)) {
    await $c.win.alert($p, "매출생성할 오더번호를 를 조회하세요");
    return;
  }
  var check = false;
  for (var i = 0; i < ds_results.getTotalRow(); i++) {
    // 엑셀업로드(915)한경우  변경할수없음
    var stateCd = ds_results.getCellData(i, "stateCd");
    if (stateCd != '0' && stateCd != '2') {
      //stateCd='0'이면 정상 ,stateCd='2'이면 전환  statecd='엑셀업로드' 이면 엑셀업로드
      await $c.win.alert($p, "엑셀업로드한 경우에는 변경할 수 없습니다.");
      return;
    }

    //confirmYn!='0'이면 확인/확정 된 데이터 경우 이므로 변경할수없음
    var confirmYn = ds_results.getCellData(i, "confirmYn"); //확인여부
    if (confirmYn != '0') {
      await $c.win.alert($p, "확인/확정 된 데이터는 변경 할 수 없습니다."); // 1은 확인, 2는확정(FPIS전송시SNDDTM값이들어가고 2로 조회됨)
      return;
    }
    var sellAmt = ds_results.getCellData(i, "sellAmt"); //sellAmt
    if (sellAmt > 0) {
      await $c.win.alert($p, "매출금액이 있는 경우 매출을 생성할 수 없습니다.");
      return;
    } else {
      check = true;
    }
  }
  if (check) {
    if (await $c.win.confirm($p, "매출금액을 생성하시겠습니까?")) {
      // ds_results.UseChangeInfo = false;
      $c.sbm.execute($p, sbm_createSellAmt);
    }
  }
};

//-------------------------------------------------------------------------
// f_Setting 
// 파주지점(8BB)인 경우,   파주지점 소속 차량의 소속거래처에 따라 자동으로 계약오더가 생성되었는데, 
// 현재 차량별 소속거래처가 실제 소속거래처가 아니라 편의상 관계없는 거래처 정보가 들어가 있는 경우가 많아서,
// 실적신고 시 운송의뢰자 정보의 수정이 필요합니다. BY 주경훈 대리 2017.09.18
//-------------------------------------------------------------------------
scwin.chkSetting = "F"; //저장 버튼 제어
scwin.f_Setting = async function () {
  //파주지점의 통오더인 경우에만 상호,사업자번호 수정되어야 함(TB_OP913)
  var chkCnt = 0;
  var chkCrn = txt_crn.getValue();
  var chkClntNo = ed_acctClntNo.getValue();
  var chkClntNm = txt_acctClntNm.getValue();
  if (chkClntNo == "" || chkClntNo == null) {
    await $c.win.alert($p, "일괄적용할 거래처를 먼저 조회해주세요.");
    ed_acctClntNo.focus();
    return false;
  }
  for (var i = 0; i < ds_results2.getTotalRow(); i++) {
    if (ds_results2.getCellData(i, "chk") == "1") {
      if (ds_results2.getCellData(i, "lobranCd") != "8BB") {
        await $c.win.alert($p, i + 1 + "번째행은 파주지점이 아닙니다. 파주지점인 경우에만 수정이 가능합니다.");
        return false;
      }
      if (ds_results2.getCellData(i, "processYn") == "3") {
        await $c.win.alert($p, i + 1 + "번째행은 엑셀업로드된 건입니다. 엑셀업로드된 경우에는 수정이 불가능합니다.");
        return false;
      }
      if (ds_results2.getCellData(i, "clsNm") != "통오더") {
        await $c.win.alert($p, i + 1 + "번째행은 통오더가 아닌 건입니다. 통오더인 경우에만 수정이 가능합니다.");
        return false;
      }
      if (ds_results2.getCellData(i, "clsNm") == "통오더" && ds_results2.getCellData(i, "lobranCd") == "8BB" && ds_results2.getCellData(i, "processYn") != "3") {
        //processYn 3 : 업로드
        ds_results2.setCellData(i, "crn", chkCrn);
        ds_results2.setCellData(i, "bilgClntNo", chkClntNo);
        ds_results2.setCellData(i, "bilgClntNm", chkClntNm);
        ds_results2.setCellData(i, "bilgClntNm2", chkClntNm);
        chkCnt++;
        scwin.chkSetting = "T";
      }
    }
  }
  if (chkCnt == 0) {
    await $c.win.alert($p, "선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
    return false;
  }
};

//-------------------------------------------------------------------------
// f_SettingSave 
// f_Setting()으로 정보 셋팅 후 실제로 저장하는 function
// *+-
//-------------------------------------------------------------------------
scwin.f_SettingSave = async function () {
  // 전송상태에서는 수정이 불가하도록 
  if (!(await scwin.f_chkBeforeSave())) {
    return;
  }
  if (scwin.chkSetting == "T") {
    if (await $c.win.confirm($p, "저장하시겠습니까??")) {
      scwin.chkSetting = "F";
      $c.sbm.execute($p, sbm_setting);
    }
  } else {
    await $c.win.alert($p, "수정된 행이 없습니다. 거래처일괄적용을 먼저 해주십시오.");
    return false;
  }
};

//----------------------------------------------------------
// f_chkBeforeSave()
// 20171127  전송상태에서는 수정이 불가하도록 변경요청  by이종훈
//----------------------------------------------------------
scwin.f_chkBeforeSave = async function () {
  var confirmYn = 0;
  for (var i = 0; i < ds_results.getTotalRow(); i++) {
    if (confirmYn < ds_results.getCellData(i, "confirmYn")) {
      confirmYn = ds_results.getCellData(i, "confirmYn");
    }
  }
  if (confirmYn == '2') {
    await $c.win.alert($p, "실적신고가 전송된 상태에서는 수정이 불가합니다.");
    return false;
  } else {
    return true;
  }
};

